module top_module(input  i_Clk,      
   input  [3:0] i_Binary_Num, 
   output o_Segment_A,
   output o_Segment_B,
   output o_Segment_C,
   output o_Segment_D,
   output o_Segment_E,
   output o_Segment_F,
   output o_Segment_G
   );reg [6:0]	inv_r_Hex_Encoding = 7'h00;

	always @(posedge i_Clk)
	begin
		case (i_Binary_Num)
		4'b0000: inv_r_Hex_Encoding <= 7'h7E;
		4'b0001: inv_r_Hex_Encoding <= 7'h30;
		4'b0010: inv_r_Hex_Encoding <= 7'h6D;
		4'b0011: inv_r_Hex_Encoding <= 7'h79;
		4'b0100: inv_r_Hex_Encoding <= 7'h33;
		4'b0101: inv_r_Hex_Encoding <= 7'h5B;
		4'b0110: inv_r_Hex_Encoding <= 7'h5F;
		4'b0111: inv_r_Hex_Encoding <= 7'h70;
		4'b1000: inv_r_Hex_Encoding <= 7'h7F;
		4'b1001: inv_r_Hex_Encoding <= 7'h7B;
		4'b1010: inv_r_Hex_Encoding <= 7'h77;
		4'b1011: inv_r_Hex_Encoding <= 7'h1F;
		4'b1100: inv_r_Hex_Encoding <= 7'h4E;
		4'b1101: inv_r_Hex_Encoding <= 7'h3D;
		4'b1110: inv_r_Hex_Encoding <= 7'h4F;
		4'b1111: inv_r_Hex_Encoding <= 7'h47;
		endcase
	end   

  assign o_Segment_A = inv_r_Hex_Encoding[6];
  assign o_Segment_B = inv_r_Hex_Encoding[5];
  assign o_Segment_C = inv_r_Hex_Encoding[4];
  assign o_Segment_D = inv_r_Hex_Encoding[3];
  assign o_Segment_E = inv_r_Hex_Encoding[2];
  assign o_Segment_F = inv_r_Hex_Encoding[1];
  assign o_Segment_G = inv_r_Hex_Encoding[0];

endmodule
